const designImportWizard=require("../../design_import_domino_wizard");const pcConstants=require("./constants");const gettingStartedConfig=require("./gettingStarted/viewConfig");const listFoundryAppConfig=require("./listFoundryApp/viewConfig");const identityServicesConfig=require("./identityServices/viewConfig");const resultConfig=require("./result/viewConfig");const showDesignConfig=require("./showDesign/viewConfig");const selectAppIdentitySvc=require("./selectedAppIdentitySvc/viewConfig");const validateFieldSelectionConfig=require("./validateFieldSelection/viewConfig");let{STEPS}=pcConstants;let Wizard=designImportWizard.getMxgoUtils().coreFunctions.wizardCore;function getWizard(e){return new Wizard(_.defaults(e,{stepsConfig:stepsConfig,id:"designImportWizard",focusElementOptions:{preventScroll:true}}))}let stepsConfig=new Map([[STEPS.GETTING_STARTED,{nextStepId:STEPS.LIST_FOUNDRY_APP,getViewConfig:gettingStartedConfig.get}],[STEPS.LIST_FOUNDRY_APP,{previousStepId:STEPS.GETTING_STARTED,nextStepId:STEPS.IDENTITY_SERVICES,getViewConfig:listFoundryAppConfig.get}],[STEPS.IDENTITY_SERVICES,{previousStepId:STEPS.LIST_FOUNDRY_APP,nextStepId:STEPS.SHOW_DESIGN,getViewConfig:identityServicesConfig.get}],[STEPS.SHOW_DESIGN,{previousStepId:STEPS.IDENTITY_SERVICES,nextStepId:STEPS.VALIDATE_FIELD_SELECTION,getViewConfig:showDesignConfig.get}],[STEPS.VALIDATE_FIELD_SELECTION,{previousStepId:STEPS.SHOW_DESIGN,nextStepId:STEPS.RESULT,getViewConfig:validateFieldSelectionConfig.get}],[STEPS.RESULT,{previousStepId:STEPS.VALIDATE_FIELD_SELECTION,getViewConfig:resultConfig.get}],[STEPS.SELECT_APP_IDENTITY_SVC,{previousStepId:STEPS.IDENTITY_SERVICES,nextStepId:STEPS.SHOW_DESIGN,getViewConfig:selectAppIdentitySvc.get}]]);module.exports={getWizard:getWizard};